import{_ as s,o as e,c as t,a0 as p}from"./chunks/framework.jwovEGr5.js";const m=JSON.parse('{"title":"ESXi 虚拟MacOS苹果系统","description":"","frontmatter":{"title":"ESXi 虚拟MacOS苹果系统","date":"2020-6-14 20:36:9","category":"ESXi","tags":["ESXi","MacOS"]},"headers":[],"relativePath":"posts/esxi-xu-ni-macos-ping-guo-xi-tong.md","filePath":"posts/esxi-xu-ni-macos-ping-guo-xi-tong.md","lastUpdated":1783006593000}'),i={name:"posts/esxi-xu-ni-macos-ping-guo-xi-tong.md"};function n(o,a,l,c,r,d){return e(),t("div",null,[...a[0]||(a[0]=[p(`<p>ESXi 6.7U3上可以非常方便的安装MacOS进行测试，这里做一下几个关键的步骤。</p><h3 id="_1、制作cdr-iso镜像" tabindex="-1">1、制作cdr/iso镜像 <a class="header-anchor" href="#_1、制作cdr-iso镜像" aria-label="Permalink to &quot;1、制作cdr/iso镜像&quot;">​</a></h3><h4 id="_1-1-首先从用apple官网下载原始文件" tabindex="-1">1.1 首先从用apple官网下载原始文件： <a class="header-anchor" href="#_1-1-首先从用apple官网下载原始文件" aria-label="Permalink to &quot;1.1 首先从用apple官网下载原始文件：&quot;">​</a></h4><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>macOS Catalina 10.15</span></span>
<span class="line"><span>https://support.apple.com/zh-cn/HT201475</span></span>
<span class="line"><span>macOS Mojave 10.14</span></span>
<span class="line"><span>https://support.apple.com/zh-cn/HT210190</span></span>
<span class="line"><span>macOS High Sierra 10.13</span></span>
<span class="line"><span>https://support.apple.com/zh-cn/HT208969</span></span>
<span class="line"><span>macOS Sierra 10.12.</span></span>
<span class="line"><span>https://support.apple.com/zh-cn/HT208202</span></span>
<span class="line"><span>OS X El Capitan 10.11</span></span>
<span class="line"><span>https://support.apple.com/zh-cn/HT206886</span></span></code></pre></div><p>或者从其他地方下载原版dmg文件，然后需要找一个macOS系统来制作cdr文件</p><h4 id="_1-2-创建一个dmg空文件" tabindex="-1">1.2 创建一个dmg空文件 <a class="header-anchor" href="#_1-2-创建一个dmg空文件" aria-label="Permalink to &quot;1.2 创建一个dmg空文件&quot;">​</a></h4><p>10.13需要5G，10.14需要6G，10.15需要8G，这里以10.14为例 然后依次为格式参数、文件系统格式 因为内存够大，所以直接挂在tmp目录，这样速度更快，如果内存不大可以自己选择文件路径</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>hdiutil create -o /tmp/Mojave.cdr -size 4g -layout SPUD -fs HFS+J</span></span></code></pre></div><h4 id="_1-3-挂载到虚拟磁盘" tabindex="-1">1.3 挂载到虚拟磁盘 <a class="header-anchor" href="#_1-3-挂载到虚拟磁盘" aria-label="Permalink to &quot;1.3 挂载到虚拟磁盘&quot;">​</a></h4><p>挂载上面新建的 dmg 镜像到虚拟磁盘，载点为 install_build，之后会使用，需要对应</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>hdiutil attach /tmp/Mojave.cdr.dmg -noverify -mountpoint /Volumes/install_build</span></span></code></pre></div><h4 id="_1-4-将下载的系统安装文件写入虚拟磁盘" tabindex="-1">1.4 将下载的系统安装文件写入虚拟磁盘 <a class="header-anchor" href="#_1-4-将下载的系统安装文件写入虚拟磁盘" aria-label="Permalink to &quot;1.4 将下载的系统安装文件写入虚拟磁盘&quot;">​</a></h4><p>将所下载的系统安装app文件写入到上面挂载的虚拟光驱磁盘中，即我们第一步建立的空镜像，首先需要输入管理员密码，然后回车，之后等待执行结束，包括擦除磁盘、复制文件、添加启动，结束之后，桌面上之前显示 untitled 的虚拟磁盘会变成我们需要的系统名称 如果是下载dmg文件，就将dmg挂载后，先把app文件复制到<strong>应用程序</strong>目录，然后将dmg取消挂载</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>sudo /Applications/Install\\ macOS\\ Mojave.app/Contents/Resources/createinstallmedia --volume /Volumes/install_build</span></span></code></pre></div><h4 id="_1-5-取消挂载建立的dmg镜像" tabindex="-1">1.5 取消挂载建立的dmg镜像 <a class="header-anchor" href="#_1-5-取消挂载建立的dmg镜像" aria-label="Permalink to &quot;1.5 取消挂载建立的dmg镜像&quot;">​</a></h4><p>取消挂载建立的dmg镜像，方便后续编辑，载点名已经从原来的install_build更改为Install macOS Mojave</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>hdiutil detach /Volumes/Install\\ macOS\\ Mojave</span></span></code></pre></div><h4 id="_1-6-格式转换" tabindex="-1">1.6 格式转换 <a class="header-anchor" href="#_1-6-格式转换" aria-label="Permalink to &quot;1.6 格式转换&quot;">​</a></h4><p>将制作好的dmg文件转换为cdr</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>mv /tmp/Mojave.cdr.dmg ~/Desktop/Mojave.dmg</span></span>
<span class="line"><span>hdiutil convert ~/Desktop/Mojave.dmg -format UDTO -o ~/Desktop/Mojave.iso</span></span></code></pre></div><h4 id="_1-7-删除dmg镜像-重命名文件" tabindex="-1">1.7 删除dmg镜像，重命名文件 <a class="header-anchor" href="#_1-7-删除dmg镜像-重命名文件" aria-label="Permalink to &quot;1.7 删除dmg镜像，重命名文件&quot;">​</a></h4><p>删除1.2建立的 dmg 镜像，释放磁盘空间 如果想保留，就不用删除</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>rm ~/Desktop/Mojave.dmg</span></span></code></pre></div><p>将cdr文件重命名为iso 实际上macos下的光盘镜像cdr格式就相当于Windows下常见的光盘镜像iso格式 在esxi中也可以直接挂载cdr文件</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>mv ~/Desktop/Mojave.iso.cdr ~/Desktop/Mojave.iso</span></span></code></pre></div><p>其他版本系统，修改相应名称即可</p><h3 id="_2、esxi补丁" tabindex="-1">2、ESXi补丁 <a class="header-anchor" href="#_2、esxi补丁" aria-label="Permalink to &quot;2、ESXi补丁&quot;">​</a></h3><p>这个补丁原作者的github已经没了，这里分享一个： esxi-unlocker-300.tgz: <a href="https://n459.com/file/20182514-448752132" target="_blank" rel="noreferrer">https://n459.com/file/20182514-448752132</a></p><p>如果不打补丁，在ESXi中创建虚拟机后，挂载iso会无限重启！</p><p>打补丁方法和前一篇文章&quot;ESXi NVME 启动降级方法&quot;类似，打开ssh，然后scp进去，再ssh登录执行即可。</p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/ESXi_%E8%99%9A%E6%8B%9FMacOS%E8%8B%B9%E6%9E%9C%E7%B3%BB%E7%BB%9F.md/1592141738733.png" alt=""></p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/ESXi_%E8%99%9A%E6%8B%9FMacOS%E8%8B%B9%E6%9E%9C%E7%B3%BB%E7%BB%9F.md/1592141950990.png" alt=""></p><p>之后重启ESXi即可</p><h3 id="_3、创建macos虚拟机" tabindex="-1">3、创建macOS虚拟机 <a class="header-anchor" href="#_3、创建macos虚拟机" aria-label="Permalink to &quot;3、创建macOS虚拟机&quot;">​</a></h3><p>之后就可以直接创建macOS虚拟机了，10.15用10.14的即可</p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/ESXi_%E8%99%9A%E6%8B%9FMacOS%E8%8B%B9%E6%9E%9C%E7%B3%BB%E7%BB%9F.md/1592142052687.png" alt=""></p><p>挂载cdr或者iso文件，显存最好设置大一些</p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/ESXi_%E8%99%9A%E6%8B%9FMacOS%E8%8B%B9%E6%9E%9C%E7%B3%BB%E7%BB%9F.md/1592142182647.png" alt=""></p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/ESXi_%E8%99%9A%E6%8B%9FMacOS%E8%8B%B9%E6%9E%9C%E7%B3%BB%E7%BB%9F.md/1592142407468.png" alt=""></p><p>安装10.14及以下版本时候需要注意，因为有证书过期的问题，会报错</p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/ESXi_%E8%99%9A%E6%8B%9FMacOS%E8%8B%B9%E6%9E%9C%E7%B3%BB%E7%BB%9F.md/1592142456969.png" alt=""></p><p>需要编辑下虚拟机设置，断开虚拟机网络，再利用&quot;实用工具-终端&quot;将时间设置到2016年2月14日之前，比如2015年</p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/ESXi_%E8%99%9A%E6%8B%9FMacOS%E8%8B%B9%E6%9E%9C%E7%B3%BB%E7%BB%9F.md/1592142509569.png" alt=""></p><p>之后退出终端再安装就行</p><h3 id="_4、vmware-tools" tabindex="-1">4、VMware Tools <a class="header-anchor" href="#_4、vmware-tools" aria-label="Permalink to &quot;4、VMware Tools&quot;">​</a></h3><p>安装完系统后，还需要安装VMware Tools增强工具，但ESXi默认没有附带macOS的。</p><p>当前vmware tools最新版本 11.1.0： <a href="https://my.vmware.com/web/vmware/details?downloadGroup=VMTOOLS1110&amp;productId=974" target="_blank" rel="noreferrer">https://my.vmware.com/web/vmware/details?downloadGroup=VMTOOLS1110&amp;productId=974</a></p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/ESXi_%E8%99%9A%E6%8B%9FMacOS%E8%8B%B9%E6%9E%9C%E7%B3%BB%E7%BB%9F.md/1592142894263.png" alt=""></p><p>这里也分享一个： VMware-Tools-darwin-11.1.0-16036546.zip: <a href="https://n459.com/file/20182514-448752130" target="_blank" rel="noreferrer">https://n459.com/file/20182514-448752130</a></p><p>解压缩将iso文件传到ESXi上，然后直接挂载安装即可</p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/ESXi_%E8%99%9A%E6%8B%9FMacOS%E8%8B%B9%E6%9E%9C%E7%B3%BB%E7%BB%9F.md/1592143042743.png" alt=""></p><p>安装完成，即可享用了。可以通过vCenter制作成模板，方便部署安装</p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/ESXi_%E8%99%9A%E6%8B%9FMacOS%E8%8B%B9%E6%9E%9C%E7%B3%BB%E7%BB%9F.md/1592143186063.png" alt=""></p>`,53)])])}const g=s(i,[["render",n]]);export{m as __pageData,g as default};
